114→fun isNonStable(version: String): Boolean {
115→  // val stableKeyword = listOf("RELEASE", "FINAL", "GA").any { version.uppercase().contains(it) }
116→  val betaKeyword = listOf("-RC", "-BETA", "-M", "-SNAPSHOT").any { version.uppercase().contains(it) }
117→  // val regex = "^[0-9,.v-]+(-r)?$".toRegex()
118→  val isStable = !betaKeyword //(stableKeyword || regex.matches(version)) && !betaKeyword
119→  return !isStable
120→}
